// \yskip\hang first byte: |width_index| (8 bits)\par
// \hang second byte: |height_index| (4 bits) times 16, plus |depth_index|
//   (4~bits)\par
// \hang third byte: |italic_index| (6 bits) times 4, plus |tag|
//   (2~bits)\par
// \hang fourth byte: |remainder| (8 bits)\par
